head.script:
//==================================================================================================================
// id       : op_203_01_06b 
// 이름     : 저수요물량지정계획등록
// 경로     : 물류/작업계획/철송
// 작 성 자 : 조성빈
// 작 업 일 : 2025-12-29
// 사용계정 : 내부
// 비고     : 
// 레포트   :
// 업로드   :
// 다운로드 : 
// 호출     :
//            
//==================================================================================================================
scwin.dateStr;
scwin.rsnCount;

scwin.onpageload = function() {
    scwin.dateStr = $c.date.getServerDateTime("yyyyMMdd");
	scwin.rsnCount = 0;
};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        $c.data.setPopupTitle("BT물량지정계획등록");

        ica_signDt.setValue(scwin.dateStr);
        acb_dptArvCls.setSelectedIndex(0);
        acb_odrRnkCd.setSelectedIndex(0);

        $p.setTimeout(function() {
            // ica_signDt.setValue("20070801");
            // ica_signDt.setValue("20070709");
            // ed_dptStnCd.setValue("6R01");
            // ed_dptStnCd.focus();
            // ed_dptStnCd.blur();
        }, {"delay":50});
    }, {"delay":50});
};

//-------------------------------------------------------------------------
// 사유화차등록결과 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function (){
    if (!await $c.gus.cfValidate([ica_signDt,  ed_dptStnCd])) {	// 신청일자
        return;
    }
    $c.sbm.execute(sbm_retrieve);
}; 

//-------------------------------------------------------------------------
// 저장버튼 처리 
//-------------------------------------------------------------------------
scwin.f_Save = async function () {		
    if(await $c.win.confirm(MSG_CM_CRM_001)){  
        $c.sbm.execute(sbm_save);
    }
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.f_FieldClear = function () {
    $c.gus.cfInitObjects(tbl_search, null);
    ica_signDt.focus();
    ica_signDt.setValue(scwin.dateStr);
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:   // 출발역 역명 팝업	
            udc_dptStn.setSelectId('retrieveTrainWorkPlace');
            udc_dptStn.cfCommonPopUp(scwin.udc_dptStn_callBackFunc	// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch					// 전체검색허용여부	("F")
                                    ,"역명조회,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 
            break;

        case 2:   // 도착역 역명 팝업	
            udc_arvStn.setSelectId('retrieveTrainWorkPlace');
            udc_arvStn.cfCommonPopUp(scwin.udc_arvStn_callBackFunc	// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch					// 전체검색허용여부	("F")
                                    ,"역명조회,작업장코드,작업장명"				// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
            ); 
        break;
    }	
};

//-------------------------------------------------------------------------
// EXCEL
//-------------------------------------------------------------------------
scwin.f_Excel = function (){
    const infoArr = [];
    const options = {
        fileName : "BT물량지정계획등록.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        sheetName: "BT물량지정계획등록",
        startRowIndex: 2,
        type : 4+8+16
    };
    $c.data.downloadGridViewExcel(gr_results, options, infoArr);
};

//--------------------------------
// 작업경로 변경 팝업
//--------------------------------
scwin.f_workPathMod = async function () {
    if (ds_results.getRowCount() == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["대상물량"]); //"선택된 @이(가) 없습니다.";
        return;
    }
    let win_url = "/ui/ds/op/wrkplan/transwrkplan/op_202_02_26p.xml";
    let data = {
          "odrNo"    : ds_results.getCellData(ds_results.getRowPosition(), "odrNo")     //오더번호
        , "cntrSeq"  : ds_results.getCellData(ds_results.getRowPosition(), "cntrSeq")   //컨테이너순번
    };
    let opts = {
        id : "workPathModPop"
        , popupName : "작업경로 변경 팝업"
        , modal : true
        , type : "browserPopup"
        , width : 840
        , height : 400
        , title : "작업경로 변경 팝업"
    };
    var rtnVal = await $c.win.openPopup(win_url, opts, data);
    //작업단계경로가 변경될 팝업후 무조건 재조회를 한다.(데이터 오류를 막기 위하여)
    if (rtnVal != 0) {
        scwin.f_Retrieve();
    }
};

scwin.f_workPathUpdate = async function () {
    for(var i = 0 ; i < ds_results.getRowCount() ; i++){
        // 0 
        if(ds_results.getRowStatus(i) != "R"){
            await $c.win.alert("BT배정을 저장한 후 작업경로 변경 하시기 바랍니다.");
            // ds_results.UndoMarked();
            ds_results.undoRow(i);
            return false;				
        }
    }
    if(await $c.win.confirm(MSG_CM_CRM_001)){  
        // ds_results.UseChangeInfo = "false";
        $c.sbm.execute(sbm_odrUpdate);
    }
}

//--------------------------------
// display setting
//--------------------------------
scwin.f_setAssgnResult = function (){
    var bt20E = 0;
    var bt20F = 0;
    var bt40E = 0;
    var bt40F = 0;
    var bt45E = 0;
    var bt45F = 0;
    var btTeu = 0;

    for(var i = 0 ; i < ds_results.getRowCount(); i++){
        if(ds_results.getCellData(i , "btAppYn" ) == "1"){
            if(ds_results.getCellData(i, "cntrSizCd") == 20 && ds_results.getCellData(i, "fullEmptyClsCd") == "E"){
                bt20E++;
                btTeu++;
            }
            if(ds_results.getCellData(i, "cntrSizCd") == 20 && ds_results.getCellData(i, "fullEmptyClsCd") == "F"){
                bt20F++;
                btTeu++;
            }
            if(ds_results.getCellData(i, "cntrSizCd") == 40 && ds_results.getCellData(i, "fullEmptyClsCd") == "E"){
                bt40E++;
                btTeu++;
                btTeu++;
            }
            if(ds_results.getCellData(i, "cntrSizCd") == 40 && ds_results.getCellData(i, "fullEmptyClsCd") == "F"){
                bt40F++;
                btTeu++;
                btTeu++;
            }
            if(ds_results.getCellData(i, "cntrSizCd") == 45 && ds_results.getCellData(i, "fullEmptyClsCd") == "E"){
                bt45E++;
                btTeu++;
                btTeu++;
            }
            if(ds_results.getCellData(i, "cntrSizCd") == 45 && ds_results.getCellData(i, "fullEmptyClsCd") == "F"){
                bt45F++;
                btTeu++;
                btTeu++;
            }
        }			
    }//for
    txt_btApp20E.setValue(bt20E); 
    txt_btApp20E.setStyle("text-decoration", "none");
    txt_btApp20F.setValue(bt20F); 
    txt_btApp20F.setStyle("text-decoration", "none");
    txt_btApp40E.setValue(bt40E); 
    txt_btApp40E.setStyle("text-decoration", "none");
    txt_btApp40F.setValue(bt40F); 
    txt_btApp40F.setStyle("text-decoration", "none");
    txt_btApp45E.setValue(bt45E); 
    txt_btApp45E.setStyle("text-decoration", "none");
    txt_btApp45F.setValue(bt45F); 
    txt_btApp45F.setStyle("text-decoration", "none");
    txt_btAppTEU.setValue(btTeu); 
    txt_btAppTEU.setStyle("text-decoration", "none");
};


