scwin.udc_dptStn_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_dptStnNm, ed_dptStnCd, 1, false);
};

scwin.udc_dptStn_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1, ed_dptStnCd.getValue(), ed_dptStnNm.getValue(), 'F', 'T');
};

scwin.udc_dptStn_onblurCodeEvent = function (e) {
    if(ed_dptStnCd.getValue() != "") scwin.f_openCommonPopUp(1, ed_dptStnCd.getValue(), ed_dptStnNm.getValue(), 'T', 'T'); 
};

scwin.udc_arvStn_onviewchangeNameEvent = function (info) {
    scwin.f_chkOpenCommonPopUp(ed_arvStnNm, ed_arvStnCd, 2, false);
};

scwin.udc_arvStn_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(2, ed_arvStnCd.getValue(), ed_arvStnNm.getValue(), 'F', 'T');
};

scwin.udc_arvStn_onblurCodeEvent = function (e) {
    if(ed_arvStnCd.getValue() != "") scwin.f_openCommonPopUp(2, ed_arvStnCd.getValue(), ed_arvStnNm.getValue(), 'T', 'T'); 
};

scwin.btn_fieldClear_onclick = function (e) {
    scwin.f_FieldClear();
};

scwin.btn_retrieve_onclick = function (e) {
    scwin.f_Retrieve();
};

scwin.btn_wrkPath_onclick = function (e) {
    scwin.f_workPathUpdate()
};

scwin.btn_save_onclick = function (e) {
    scwin.f_Save()
};

scwin.sbm_retrieve_submit = function (e) {
    ds_condition.set("signDt", ica_signDt.getValue());
	ds_condition.set("dptStnCd", ed_dptStnCd.getValue());
    ds_condition.set("arvStnCd", ed_arvStnCd.getValue());
	ds_condition.set("planAssgnYn", acb_dptArvCls.getValue());
	ds_condition.set("odrRnkCd", acb_odrRnkCd.getValue());

};

scwin.sbm_retrieve_submitdone = async function (e) {
    var rowCnt = ds_results.getRowCount();
  	if( rowCnt == 0 ){
		await $c.gus.cfAlertMsg("[조회된 데이터가] " + MSG_CM_ERR_003);
		return false;
  	}
  	//batch가 끝난후에는 배정은 수정가능, 지정은 수정불가 
	if(ds_results.getCellData(0, "btBatchRunYn") == "COMPLETED"){
        gr_results.setColumnReadOnly("btAppYn", true);
        gr_results.setColumnReadOnly("btAppConse", false);
  		$c.gus.cfEnableObjects([btn_wrkPath]);
  	}else{
        gr_results.setColumnReadOnly("btAppYn", false);
        gr_results.setColumnReadOnly("btAppConse", true);
  		$c.gus.cfDisableObjects([btn_wrkPath]);
  	}
    txt_totalRows.setValue(rowCnt);
  	scwin.f_setAssgnResultConse();
  	scwin.rsnCount = ds_results.getCellData(0, "rsnRightVsslAppYnCnt");

    // decode('rsltsAssgnYn','N','under','')
    for (var i = 0; i < rowCnt; i++){
        if(ds_results.getCellData(i, "rsltsAssgnYn") == "N"){
            gr_results.setCellStyle(i, "cntrNo", "text-decoration", "underline");
        }
    }
};

scwin.sbm_retrieve_submiterror = function (e) {

};

scwin.sbm_save_submit = function (e) {

};

scwin.sbm_save_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001); 
    $c.sbm.execute(sbm_retrieve);

};

scwin.sbm_save_submiterror = function (e) {

};

scwin.sbm_odrUpdate_submit = function (e) {

};

scwin.sbm_odrUpdate_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_001); 
    $c.sbm.execute(sbm_retrieve);
    // ds_results.UseChangeInfo = "true";

};

scwin.sbm_odrUpdate_submiterror = function (e) {
    // ds_results.UseChangeInfo = "true";
};

scwin.gr_results_oncellclick = async function (row, columnIndex, colid) {
    if(colid == "btAppYn" || colid == "btAppConse"){
		scwin.f_setAssgnResult();  
	    //적재내역이 등록되어 있으면 BT, 우선권 배정 선택 불가
	    if(ds_results.getCellData(row, "rsltsAssgnYn") == "Y"){
	    	await $c.win.alert("적재내역등록이 끝난 컨테이너는 선택할 수 없습니다.");
	    	// ds_results.UndoMarked();
            ds_results.undoRow(row);
	    }
	  	//BT와 우선권 배정 둘다 선택할 수 없다.
	  	if(ds_results.getCellData(row, "rsnRightVsslAppYn") == "1"){
	  		await $c.win.alert("BT와 우선권 배정을 하나의 컨테이너에 대해서 동시에 진행할 수 없습니다.");
	  		// ds_results.UndoMarked();
            ds_results.undoRow(row);
	  	}
	  	if(colid == "btAppConse" && ds_results.getCellData(row, "btAppConse") == "T"){ // T
	  		ds_results.setCellData(row, "btAppYn", 1);
	  	}
	  	if(colid == "btAppConse" && ds_results.getCellData(row, "btAppConse") == "N"){ // F
	  		ds_results.setCellData(row, "btAppYn", 0);
	  	}
	  	scwin.f_setAssgnResult();
	}
};

scwin.gr_results_oncelldblclick = function (row, columnIndex, colid) {
    if (colid == "cntrNo") {
		if(ds_results.getCellData(row, "rsltsAssgnYn") == "N"){
			var dptStnCd = ds_results.getCellData(row, "dptWrkPlCd");
			var arvStnCd = ds_results.getCellData(row, "arvWrkPlCd");
			var onReqDt = ica_signDt.getValue();
			var cntrNo = ds_results.getCellData(row, "cntrNo");

            let src = "/ui/ds/op/wrkrslts/railroadwrkrslts/op_205_01_01b.xml";
            let menuNm = "적재내역등록";
            let menuId = "op_205_01_01b";

            paramObj = {};
            paramObj.pgmInfo = {
                  dptStnCd    : dptStnCd
                , arvStnCd    : arvStnCd
                , onReqDt     : onReqDt
                , cntrNo      : cntrNo
            };
            $c.win.openMenu(menuNm, src, menuId, paramObj);

		}
	}
};

